import { useEffect, useState } from 'react'
import { GetContacts, GetGroups, DeleteContacts, SearchContacts } from '../../../wailsjs/go/main/App'
import { useContactStore } from '../../stores/contactStore'
import type { Group } from '../../types'
import ContactEditModal from './ContactEditModal'
import type { Contact } from '../../types'

export default function ContactList() {
  const {
    contacts,
    selectedIds,
    currentGroupId,
    searchQuery,
    setContacts,
    toggleSelected,
    selectAll,
    clearSelection,
    setCurrentGroupId,
    setSearchQuery,
  } = useContactStore()

  const [groups, setGroups] = useState<Group[]>([])
  const [loading, setLoading] = useState(false)
  const [editTarget, setEditTarget] = useState<Contact | null | undefined>(undefined)
  // undefined = モーダル非表示, null = 新規作成, Contact = 編集

  // グループ一覧取得
  useEffect(() => {
    GetGroups().then(setGroups).catch(console.error)
  }, [])

  // 連絡先一覧取得
  useEffect(() => {
    setLoading(true)
    const fetch = searchQuery
      ? SearchContacts(searchQuery)
      : GetContacts(currentGroupId)
    fetch
      .then(setContacts)
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [currentGroupId, searchQuery])

  const handleDelete = async () => {
    if (selectedIds.size === 0) return
    const ids = Array.from(selectedIds)
    await DeleteContacts(ids)
    clearSelection()
    const updated = await GetContacts(currentGroupId)
    setContacts(updated)
  }

  const handleSaved = async () => {
    setEditTarget(undefined)
    clearSelection()
    const updated = await GetContacts(currentGroupId)
    setContacts(updated)
  }

  const tabs = [{ id: '', name: 'すべて' }, ...groups]

  return (
    <div className="flex flex-col h-full">
      {/* 検索バー */}
      <div className="p-3 border-b border-gray-200">
        <input
          type="text"
          placeholder="検索..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="w-full px-3 py-1.5 text-sm border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {/* グループタブ */}
      <div className="flex overflow-x-auto border-b border-gray-200 px-2 pt-1 gap-1">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => {
              setCurrentGroupId(tab.id)
              setSearchQuery('')
            }}
            className={`px-3 py-1.5 text-xs rounded-t-md whitespace-nowrap transition-colors ${
              currentGroupId === tab.id && !searchQuery
                ? 'bg-blue-50 text-blue-700 font-medium border-b-2 border-blue-500'
                : 'text-gray-500 hover:text-gray-700'
            }`}
          >
            {tab.name}
          </button>
        ))}
      </div>

      {/* 全選択/全解除 */}
      <div className="flex items-center justify-between px-3 py-1.5 border-b border-gray-100 text-xs text-gray-500">
        <span>{selectedIds.size > 0 ? `${selectedIds.size} 件選択中` : `${contacts.length} 件`}</span>
        <div className="flex gap-2">
          <button onClick={selectAll} className="hover:text-blue-600">全選択</button>
          <button onClick={clearSelection} className="hover:text-blue-600">解除</button>
        </div>
      </div>

      {/* 連絡先リスト */}
      <div className="flex-1 overflow-y-auto">
        {loading && (
          <div className="text-center py-8 text-sm text-gray-400">読み込み中...</div>
        )}
        {!loading && contacts.length === 0 && (
          <div className="text-center py-8 text-sm text-gray-400">
            {searchQuery ? '検索結果がありません' : '連絡先がありません'}
          </div>
        )}
        {!loading && contacts.map((c) => (
          <div
            key={c.id}
            onDoubleClick={() => setEditTarget(c)}
            className={`flex items-start gap-2 px-3 py-2.5 border-b border-gray-100 cursor-pointer hover:bg-gray-50 ${
              selectedIds.has(c.id) ? 'bg-blue-50' : ''
            }`}
          >
            <input
              type="checkbox"
              checked={selectedIds.has(c.id)}
              onChange={() => toggleSelected(c.id)}
              onClick={(e) => e.stopPropagation()}
              className="mt-1 h-3.5 w-3.5 accent-blue-600"
            />
            <div className="flex-1 min-w-0">
              <div className="flex items-baseline gap-1">
                <span className="text-sm font-medium text-gray-800">
                  {c.familyName} {c.givenName}
                </span>
                <span className="text-xs text-gray-400">{c.honorific}</span>
              </div>
              {c.company && (
                <div className="text-xs text-gray-500 truncate">{c.company}</div>
              )}
              <div className="text-xs text-gray-400 truncate">
                {c.postalCode && `〒${c.postalCode} `}
                {c.prefecture}{c.city}{c.street}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* フッターボタン */}
      <div className="p-2 border-t border-gray-200 flex gap-2">
        <button
          onClick={() => setEditTarget(null)}
          className="flex-1 py-1.5 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors"
        >
          + 新規追加
        </button>
        {selectedIds.size > 0 && (
          <button
            onClick={handleDelete}
            className="px-3 py-1.5 text-sm bg-red-50 text-red-600 border border-red-200 rounded-md hover:bg-red-100 transition-colors"
          >
            削除 ({selectedIds.size})
          </button>
        )}
      </div>

      {/* 編集モーダル */}
      {editTarget !== undefined && (
        <ContactEditModal
          contact={editTarget ?? undefined}
          onClose={() => setEditTarget(undefined)}
          onSaved={handleSaved}
        />
      )}
    </div>
  )
}

import { useState } from 'react'
import { SaveContact } from '../../../wailsjs/go/main/App'
import type { Contact } from '../../types'

interface Props {
  contact?: Contact  // undefined = 新規作成
  onClose: () => void
  onSaved: () => void
}

const HONORIFICS = ['様', '殿', '御中', '先生']

function emptyContact(): Omit<Contact, 'id' | 'createdAt' | 'updatedAt'> {
  return {
    familyName: '',
    givenName: '',
    familyNameKana: '',
    givenNameKana: '',
    honorific: '様',
    postalCode: '',
    prefecture: '',
    city: '',
    street: '',
    building: '',
    company: '',
    department: '',
    notes: '',
  }
}

export default function ContactEditModal({ contact, onClose, onSaved }: Props) {
  const isNew = !contact
  const [form, setForm] = useState<Omit<Contact, 'id' | 'createdAt' | 'updatedAt'>>(
    contact
      ? {
          familyName: contact.familyName,
          givenName: contact.givenName,
          familyNameKana: contact.familyNameKana,
          givenNameKana: contact.givenNameKana,
          honorific: contact.honorific,
          postalCode: contact.postalCode,
          prefecture: contact.prefecture,
          city: contact.city,
          street: contact.street,
          building: contact.building,
          company: contact.company,
          department: contact.department,
          notes: contact.notes,
        }
      : emptyContact()
  )
  const [errors, setErrors] = useState<Partial<Record<keyof typeof form, string>>>({})
  const [saving, setSaving] = useState(false)

  const set = (field: keyof typeof form) => (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setForm((prev) => ({ ...prev, [field]: e.target.value }))
    setErrors((prev) => ({ ...prev, [field]: undefined }))
  }

  const validate = () => {
    const errs: typeof errors = {}
    if (!form.familyName.trim()) errs.familyName = '姓は必須です'
    if (!form.givenName.trim()) errs.givenName = '名は必須です'
    return errs
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    const errs = validate()
    if (Object.keys(errs).length > 0) {
      setErrors(errs)
      return
    }
    setSaving(true)
    try {
      await SaveContact({
        id: contact?.id ?? '',
        createdAt: contact?.createdAt ?? '',
        updatedAt: contact?.updatedAt ?? '',
        ...form,
      })
      onSaved()
    } catch (err) {
      console.error(err)
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50" onClick={onClose}>
      <div
        className="bg-white rounded-lg shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
      >
        {/* ヘッダー */}
        <div className="flex items-center justify-between px-5 py-3 border-b border-gray-200">
          <h2 className="text-base font-semibold text-gray-800">
            {isNew ? '連絡先を追加' : '連絡先を編集'}
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 text-xl leading-none">&times;</button>
        </div>

        {/* フォーム */}
        <form onSubmit={handleSubmit} className="p-5 space-y-4">
          {/* 氏名 */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="姓" required error={errors.familyName}>
              <input
                type="text"
                value={form.familyName}
                onChange={set('familyName')}
                className={inputCls(!!errors.familyName)}
                placeholder="田中"
              />
            </Field>
            <Field label="名" required error={errors.givenName}>
              <input
                type="text"
                value={form.givenName}
                onChange={set('givenName')}
                className={inputCls(!!errors.givenName)}
                placeholder="太郎"
              />
            </Field>
          </div>

          {/* 氏名かな */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="姓（かな）">
              <input type="text" value={form.familyNameKana} onChange={set('familyNameKana')} className={inputCls()} placeholder="たなか" />
            </Field>
            <Field label="名（かな）">
              <input type="text" value={form.givenNameKana} onChange={set('givenNameKana')} className={inputCls()} placeholder="たろう" />
            </Field>
          </div>

          {/* 敬称 */}
          <Field label="敬称" required>
            <select value={form.honorific} onChange={set('honorific')} className={inputCls()}>
              {HONORIFICS.map((h) => (
                <option key={h} value={h}>{h}</option>
              ))}
            </select>
          </Field>

          {/* 郵便番号 */}
          <Field label="郵便番号">
            <input
              type="text"
              value={form.postalCode}
              onChange={set('postalCode')}
              className={inputCls()}
              placeholder="1000001"
              maxLength={8}
            />
          </Field>

          {/* 都道府県・市区町村 */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="都道府県">
              <input type="text" value={form.prefecture} onChange={set('prefecture')} className={inputCls()} placeholder="東京都" />
            </Field>
            <Field label="市区町村">
              <input type="text" value={form.city} onChange={set('city')} className={inputCls()} placeholder="千代田区" />
            </Field>
          </div>

          {/* 番地 */}
          <Field label="番地">
            <input type="text" value={form.street} onChange={set('street')} className={inputCls()} placeholder="1-1-1" />
          </Field>

          {/* 建物名 */}
          <Field label="建物名">
            <input type="text" value={form.building} onChange={set('building')} className={inputCls()} placeholder="○○ビル 101" />
          </Field>

          {/* 会社名・部署 */}
          <div className="grid grid-cols-2 gap-3">
            <Field label="会社名">
              <input type="text" value={form.company} onChange={set('company')} className={inputCls()} />
            </Field>
            <Field label="部署名">
              <input type="text" value={form.department} onChange={set('department')} className={inputCls()} />
            </Field>
          </div>

          {/* メモ */}
          <Field label="メモ">
            <textarea
              value={form.notes}
              onChange={set('notes')}
              rows={2}
              className={`${inputCls()} resize-none`}
            />
          </Field>

          {/* ボタン */}
          <div className="flex justify-end gap-2 pt-1">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-1.5 text-sm text-gray-600 border border-gray-300 rounded-md hover:bg-gray-50"
            >
              キャンセル
            </button>
            <button
              type="submit"
              disabled={saving}
              className="px-4 py-1.5 text-sm bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
            >
              {saving ? '保存中...' : '保存'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

function Field({
  label,
  required,
  error,
  children,
}: {
  label: string
  required?: boolean
  error?: string
  children: React.ReactNode
}) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 mb-1">
        {label}
        {required && <span className="text-red-500 ml-0.5">*</span>}
      </label>
      {children}
      {error && <p className="mt-1 text-xs text-red-500">{error}</p>}
    </div>
  )
}

function inputCls(hasError = false) {
  return `w-full px-2.5 py-1.5 text-sm border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 ${
    hasError ? 'border-red-400' : 'border-gray-300'
  }`
}

